<script setup lang="ts">
import { ref, computed, onMounted, onBeforeUnmount } from 'vue';
import { useDataStore } from './store';

const store = useDataStore() as any;

const modeMap: Record<string, string> = {
  N: 'N', 普通: 'N', 日常: 'N', 常服: 'N',
  neishe: 'neishe', 内射: 'neishe', 中出: 'neishe',
  rimjob: 'rimjob', 舔肛: 'rimjob', 肛舔: 'rimjob',
  shenhou: 'shenhou', 深喉: 'shenhou',
};
const mode = computed(() => {
  const raw = String(store.当前立绘模式 ?? 'N').trim();
  return modeMap[raw] ?? 'N';
});
const modeLabel = computed(() => (mode.value === 'N' ? '日常立绘' : '密事立绘'));

const portraitBase = 'https://cdn.jsdelivr.net/gh/ywclgl258/touxiang@main';
const slugMap: Record<string, string> = {
  慕紫衣: 'mu',
  柳辞镜: 'liu',
  白霜雪: 'bai',
  苏晚晴: 'su',
  蓝若溪: 'lan',
  金瑶: 'jin',
};
const allChars = ['慕紫衣', '柳辞镜', '白霜雪', '苏晚晴', '蓝若溪', '金瑶'] as const;
const presentChars = computed(() =>
  allChars.filter((name) => Boolean(store[name]?.是否在场)).map((name) => ({ name }))
);

const events = computed(() => {
  const out: { name: string; detail: string }[] = [];
  for (let i = 1; i <= 2; i++) {
    const name = String(store.主角?.[`重要事件${i}_名称`] ?? '无').trim();
    const detail = String(store.主角?.[`重要事件${i}_情况`] ?? '无').trim();
    if (name && name !== '无') out.push({ name, detail });
  }
  return out;
});

const portraitUrl = (ch: { name: string }) => {
  const slug = slugMap[ch.name] ?? 'jin';
  const n = Math.floor(Math.random() * 10) + 1;
  return `${portraitBase}/${slug}/${mode.value}%20(${n}).png`;
};

// 心声从最近 AI 消息提取
const voices = ref<Record<string, string>>({});

function findLatestAiMes(): any | null {
  try {
    const ST = (window.parent && (window.parent as any).SillyTavern) || (window as any).SillyTavern;
    if (!ST || typeof ST.getContext !== 'function') return null;
    const ctx = ST.getContext();
    if (!ctx || !Array.isArray(ctx.chat)) return null;
    for (let i = ctx.chat.length - 1; i >= 0; i--) {
      const m = ctx.chat[i];
      if (m && !m.is_user) return m;
    }
  } catch (e) {
    /* ignore */
  }
  return null;
}

function parseVoices(mes: any): Record<string, string> {
  const out: Record<string, string> = {};
  if (!mes) return out;
  const text: string = mes.mes || mes.message || '';
  const re = /<心声([^>\s]+)>([\s\S]*?)<\/心声\1>/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(text)) !== null) {
    const name = m[1];
    const content = (m[2] || '').trim();
    if (content) out[name] = content;
  }
  return out;
}

function refreshVoices() {
  voices.value = parseVoices(findLatestAiMes());
}

function bindActions(root: ParentNode) {
  const btns = root.querySelectorAll<HTMLButtonElement>('.dx-action[data-msg]');
  btns.forEach((btn) => {
    if ((btn as any).__dxBound) return;
    (btn as any).__dxBound = true;
    btn.addEventListener('click', () => {
      const rootDoc = (window.parent && window.parent !== window ? (window.parent as any).document : document) as Document;
      const ta =
        rootDoc.querySelector<HTMLTextAreaElement>('#send_textarea') ||
        rootDoc.querySelector<HTMLTextAreaElement>('textarea[name="text_input"]') ||
        rootDoc.querySelector<HTMLTextAreaElement>('textarea.send_textarea') ||
        rootDoc.querySelector<HTMLTextAreaElement>('.send_textarea textarea') ||
        rootDoc.querySelector<HTMLTextAreaElement>('textarea');
      if (!ta) {
        flashBtn(btn, '✗ 未找到酒馆输入框', false);
        return;
      }
      const msg = btn.getAttribute('data-msg') || btn.innerText || '';
      ta.focus();
      ta.value = msg;
      try {
        ta.dispatchEvent(new Event('input', { bubbles: true }));
        ta.dispatchEvent(new Event('change', { bubbles: true }));
      } catch (e) { /* ignore */ }
      ta.setSelectionRange(ta.value.length, ta.value.length);
      if (typeof ta.scrollTop !== 'undefined') ta.scrollTop = ta.scrollHeight;
      flashBtn(btn, '✓ 已填入酒馆输入框', true);
    });
  });
}

function flashBtn(btn: HTMLButtonElement, msg: string, ok: boolean) {
  const b = btn.querySelector('b');
  const saved = b?.innerHTML ?? '';
  if (b) b.innerHTML = msg;
  const prev = { color: btn.style.color, border: btn.style.borderColor, bg: btn.style.background };
  btn.style.color = ok ? '#2e5b4a' : '#a72d27';
  btn.style.borderColor = ok ? 'rgba(82,122,104,.75)' : 'rgba(167,45,39,.75)';
  btn.style.background = ok ? 'rgba(243,250,238,.95)' : 'rgba(255,238,236,.95)';
  setTimeout(() => {
    btn.style.color = prev.color;
    btn.style.borderColor = prev.border;
    btn.style.background = prev.bg;
    if (b) b.innerHTML = saved;
  }, 1200);
}

let refreshTimer: ReturnType<typeof setInterval> | null = null;

onMounted(() => {
  // 等待 Vue 完成 DOM 渲染
  requestAnimationFrame(() => {
    bindActions(document);
    refreshVoices();
  });
  // 每 1.5 秒尝试刷新心声(覆盖多轮回复)
  refreshTimer = setInterval(refreshVoices, 1500);
  window.addEventListener('dx-refresh-voices', refreshVoices);
  document.addEventListener('visibilitychange', () => {
    if (!document.hidden) refreshVoices();
  });
});

onBeforeUnmount(() => {
  if (refreshTimer) clearInterval(refreshTimer);
  window.removeEventListener('dx-refresh-voices', refreshVoices);
});
</script>

